import json
with open('baseline-packages.json') as f: before = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                pkgs[key] = pkg['resolvedVersion']
    return pkgs

b = extract(before)
a = extract(after)

print('CHANGES:')
for k in sorted(set(b.keys()) | set(a.keys())):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        print(f'  {k[0]} ({k[1]}): {k[2]} {bv} -> {av}')

print()
print('UNCHANGED:')
count = 0
for k in sorted(set(b.keys()) & set(a.keys())):
    if b[k] == a[k]:
        count += 1
print(f'  {count} packages unchanged')
"

